var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"수, 수아야!","JPN":"コ、コトリちゃん！","ENG":"S-Skia!","TWN":"蘇…蘇亞！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"시스템 재부팅이 생각보다 오래 걸렸네. 상황이 끝났을 줄은 몰랐어.","JPN":"システムの再起動に思ったよりも時間がかかったね。\\n状況が終わっているとは予想できなかったよ。","ENG":"Rebooting the system took longer than expected. I did not expect the situation to be over.","TWN":"系統重啟的時間有點久，竟然都處理完了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"아니면…… 너희가 금방 끝낸 건가?","JPN":"それとも……アナタたちが終わらせるのが早かった？","ENG":"Or... Did you guys take care of it quickly?","TWN":"還是……是你們動作太快？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"수아야! 괜찮은 거야?","JPN":"コトリ！　大丈夫？","ENG":"Skia! Are you all right?","TWN":"蘇亞！你沒事嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"아까 초기화 한다고 그러지 않았어……?","JPN":"さっき初期化って言ってなかった……？","ENG":"Didn’t they say that they were resetting you?","TWN":"他們剛剛不是說把你初始化嗎……？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"언젠가 이런 일이 벌어질 걸 계산했어. 행동을 보면 생각이 읽히니까.","JPN":"いつかこんなことも起こり得ることを計算してた。\\n行動を見れば考えが読めるから。","ENG":"I calculated that this would happen someday. If you see their actions, you can determine their thoughts.","TWN":"我早就料到會有這種事發生，因為從他們的行動，就可以知道他們在想什麼。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"단순히 초기화 버튼하고 재부팅 버튼 위치를 바꿨을 뿐인데. 전혀 눈치 못 챘나 봐.","JPN":"単純に初期化ボタンと再起動ボタンの位置を入れ替えただけなのに。全然気づかなかったみたい。","ENG":"I simply changed the locations of the reset button and the reboot button. They must not have caught on.","TWN":"於是我就將初始化和重啟按鈕的位置對調，看來他們完全沒發現。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"와…… 수아 멋있어. 그런 것도 할 줄 알고…….","JPN":"わぁ……コトリちゃんかっこいい。そんなこともできるんだ……","ENG":"You’re amazing Skia... You even know how to do that.","TWN":"哇……蘇亞你好厲害喔，竟然還有這招……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그러게. 만지는 기계마다 고장난다고 건들지도 않으려고 했는데.","JPN":"そうだな。機械は触ると壊れるからって触れようとすらしてなかったのに。","ENG":"Tell me about it. You said that every machine you touch breaks down, so you tried to avoid touching them at all.","TWN":"對啊，你之前還說被你碰過的機器都會壞掉，所以不想碰的。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"뇌에 기계를 연결했으니까 나도 적용을…… 아니 적응을 할 수 있게 된 거지.","JPN":"脳に機械を繋いでいるからワタシも適用……いや、適応してきたんだと思う。","ENG":"Since a machine is connected to my brain, I also applied... I mean I adapted to it.","TWN":"畢竟我的腦袋現在就連接著機器……自然而然會適應吧？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"이게…… 무슨 감정인지는 제대로 말하기 어렵지만.","JPN":"これが……どんな感情かは言葉にしづらいけど。","ENG":"Although I cannot explain what emotion this is.","TWN":"這種感覺……不太好形容。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"지금도 괜찮아. 나름 알아볼 수 있는 보조 장치도 있고.","JPN":"今のままでもいいよ。それなりに伝わる補助装置もあるし。","ENG":"It’s good as it is. There’s even a support device that shows them relatively well.","TWN":"沒關係，有可以明白你的感覺的輔助裝置。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그나저나 그 사람들…… 우릴 쫓아올까?","JPN":"それにしてもあの人たち……私たちを追いかけてくるのかな？","ENG":"By the way, those people... Will they chase after us?","TWN":"不過……那些人會來抓我們嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"확률은 있지만, 현장을 보면…… 몸 사릴 시간은 있지 않을까 싶네.","JPN":"可能性はあるけど、現場を見れば……\\nしばらく休める時間はあるんじゃないかな。","ENG":"There is a probability but once they see this scene... I think we may have some time to catch our breath.","TWN":"有可能，不過從現場的情況看來……我們或許還有一些時間可以脫身。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"워낙 참혹해서 말이지.","JPN":"見るも無残な状況だからね。","ENG":"It is quite a messy scene.","TWN":"畢竟現場慘不忍睹。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그, 그런가…….","JPN":"そ、そうかな……","ENG":"Y-you think so?","TWN":"是嗎……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그래도 대비는 해야 할 거야. 집요한 놈들인 거 잘 알잖아.","JPN":"でも何かしら備えるべきだと思う。しつこい連中ってことはよくわかってるでしょ。","ENG":"We should still be prepared. You know fully well that they’re a stubborn bunch.","TWN":"我們還是必須有備無患，你也知道那些傢伙有多死纏爛打！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"도망친 애들 싹 다 잡아 갔지.","JPN":"逃げた子たちだって全員捕まっちゃったし。","ENG":"They captured all the kids who ran away.","TWN":"逃走的人都會被他們一個一個抓回來。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"……그걸 우리가 도왔고.","JPN":"……それを私たちは手伝ってた。","ENG":"...And we helped them.","TWN":"……而且我們還是幫兇呢！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"내 손으로 애들을 잡아다 넘겼어. 아까 그 애도 그렇고…….","JPN":"この手であの子たちを捕まえたんだ。さっきの子もそうだったし……","ENG":"I caught those kids and passed them over with my own hands. Just like that girl from earlier...","TWN":"是我親手把那些孩子抓回來，交到他們手裡的，剛剛那個孩子也是……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"미안하다면 다시 구해 오면 돼.","JPN":"申し訳ないと思うなら、また助けてあげればいい。","ENG":"If you feel sorry, then you can help rescue them again.","TWN":"要是覺得良心過意不去，就再把他們救出來。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"<color=#ffd34c> 프로젝트 오즈</color>. 이번에는 아이들을 구출해 오는 계획이야.","JPN":"<color=#ffd34c>プロジェクト・オズ</color>。今度は子どもたちの救出計画だよ。","ENG":"<color=#ffd34c> Project OZ</color>. This time, the plan is to rescue the kids.","TWN":"<color=#ffd34c>奧茲國計畫</color>。這次的計畫是將孩子們救出來。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그럴까? 하지만 우리가 어떻게…….","JPN":"そうしよう。でも私たちはどうすれば……","ENG":"Should we do that? But how can we...","TWN":"是嗎？但是光憑我們……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"그 애가 말했던 관리국 사람한테 도움을 요청해 보는 건 어때?","JPN":"あの子が言ってた管理局の人に助けを求めてみるのはどう？","ENG":"How about we ask for help from the Administration agent the girl mentioned?","TWN":"那個孩子不是有提到管理局的人嗎？還是我們去向她求助呢？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"하지만 누군지 알고? 알아도, 연락은 어떻게 하려고.","JPN":"でも誰だか知らないんだよね。\\nわかったとしても、どうやって連絡する？","ENG":"But we don’t even know who it is. Even if we knew, how are we supposed to contact the agent?","TWN":"你知道他是誰嗎？就算知道，但要怎麼聯絡呢？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"응? 어디서 진동이……?","JPN":"あれ？　どこからか振動音が……？","ENG":"Huh? Where’s this vibration coming from...?","TWN":"嗯？怎麼會有震動聲……？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"도로시. 네 주머니.","JPN":"ドロシー、アナタのポケット。","ENG":"Dorothy. Your pocket.","TWN":"桃樂絲，你的口袋。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"엥?","JPN":"え？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"핸드폰? 내 건 아닌데?","JPN":"携帯？　私のじゃないよ？","ENG":"Smartphone? But this isn’t mine.","TWN":"怎麼會有手機？這不是我的？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"설마…… 아까 <color=#ffd34c>그 애</color>가?","JPN":"まさか……さっき<color=#ffd34c>あの子</color>が？","ENG":"Could this belong to... <color=#ffd34c>the girl</color> from earlier?","TWN":"難道是……剛剛那個<color=#ffd34c>孩子</color>？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"얼른 받아봐. 끊기겠어.","JPN":"切れる前に早く出てみて。","ENG":"Take the call before they hang up.","TWN":"你快接起來。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"어어.","JPN":"あ、うん。","ENG":"...Err?","TWN":"喔喔，好。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWORD_OZ_NULL_FAKE","text":{"KOREA":"대체 어디 있는 거야? 약속 장소에도 없고, 연락도 안 받고!","JPN":"いったいどこにいるの？\\n待ち合わせ場所にもいないし、電話にも出ないし！","ENG":"Where are you? You aren’t at the rendezvous point, you aren’t picking up...","TWN":"你現在人在哪裡？我在約好的地點沒看到你，打電話又不接！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWORD_OZ_NULL_FAKE","text":{"KOREA":"설마 다시 거기로 돌아간 건 아니지? 얼마나 위험한 데인지는 본인이 더 잘 알 테니까.","JPN":"まさかまたあそこに戻ったんじゃないわよね？\\nどれだけ危険な場所なのかはあんたのほうがわかっていると思うけど。","ENG":"Don’t tell me you went back there?! You know better than I do how dangerous that place is.","TWN":"你該不會又回去了吧？那個地方有多危險，你應該比我更清楚吧？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"저기.","JPN":"あの。","ENG":"Hey.","TWN":"請問，"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"혹시 관리국 사람이야?","JPN":"もしかして管理局の人？","ENG":"Are you from the Administration?","TWN":"你是管理局的人嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWORD_OZ_NULL_FAKE","text":{"KOREA":"……만나기로 했던 애가 아닌 것 같은데? 너 누구야?","JPN":"……待ち合わせ予定の子じゃないみたいね。あんたは誰？","ENG":"...You’re not the one I was supposed to meet. Identify yourself.","TWN":"……你似乎不是我要找的人？你是誰？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"핸드폰 주인의 친구…… 라고 해도 될지 모르겠네. 일단은 그 애를 구하고 싶은 사람이야.","JPN":"この携帯の持ち主の友達……と言っていいのかわからないけど。\\n一応、その子を救いたいと思ってる人。","ENG":"I’m not sure if I could say that I’m... a friend of this device’s owner. But I am someone who wants to rescue her.","TWN":"我是手機主人的朋友……吧？總之我是想救她的人啦！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그러기 위해선…… 도움이 필요해.","JPN":"そのためには……助けが必要なんだ。","ENG":"In order to do that... I need help.","TWN":"所以……我們需要協助！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWORD_OZ_NULL_FAKE","text":{"KOREA":"흐응……. 구한다는 표현을 쓰는 것 보니 <color=#ffd34c>위저드</color>에 대해 어느 정도 아는 모양이네.","JPN":"ふーん……救いたいと言ってるってことは、<color=#ffd34c>ウィザード</color>についてある程度知っているようね。","ENG":"Hmm... Seeing that you said “rescue”, you seem to know a bit about <color=#ffd34c>Wizard</color>.","TWN":"嗯……你會使用\\"救\\"這個詞，就表示對<color=#ffd34c>魔法師</color>有一定程度的認識。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWORD_OZ_NULL_FAKE","text":{"KOREA":"그런데 널 어떻게 믿고?","JPN":"で、あんたを信用できる証拠は？","ENG":"However, how can I trust you?","TWN":"不過我憑什麼要相信你？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"방금 좌표 보냈어. 그곳에서 <color=#ffd34c>위저드</color>하고 싸웠으니까 확인해 봐.","JPN":"今座標を送った。そこで<color=#ffd34c>ウィザード</color>と戦ったから確かめてみて。","ENG":"I just sent you coordinates where we fought <color=#ffd34c>Wizard</color>. Take a look.","TWN":"我剛有把座標發給你，我們在那裡和<color=#ffd34c>魔法師</color>交手，你再確認一下。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L4_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"수아야?","JPN":"コトリ？","ENG":"Skia?","TWN":"蘇亞？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"핸드폰은 파기할게. 대신 개인 메신저 링크와 보안 코드를 보낼 테니 그쪽으로 연락해 줘.","JPN":"携帯電話は破棄する。代わりに個人メッセンジャーのリンクとセキュリティコードを送るから、そちらに連絡してほしい。","ENG":"We will discard the phone. Instead, I will send you personal messenger links and security codes. Contact us there.","TWN":"手機我們會銷毀，改用個人通訊連結和密碼聯絡，資訊我會發給你。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"우리도 위치가 노출되면 안 되는 상황이라.","JPN":"ワタシたちも居場所が特定されるとまずい状況だから。","ENG":"We also cannot expose our location at the moment.","TWN":"我們現在也不方便暴露位置。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SWORD_OZ_NULL_FAKE","text":{"KOREA":"……좋아. 알겠어.","JPN":"……いいわ。わかった。","ENG":"...Understood. I’ll do that.","TWN":"……好，沒問題！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWORD_OZ_NULL_FAKE","text":{"KOREA":"코드 네임은 <color=#ffd34c>레드 리코리스</color>야. 다시 만날 때까지 기억해 둬.","JPN":"コードネームは<color=#ffd34c>レッドリコリス</color>よ。次に会うまでに覚えておいて。","ENG":"My code name is <color=#ffd34c>Red Lycoris</color>. Remember it until we meet again.","TWN":"密碼是<color=#ffd34c>紅髮莉克麗絲</color>，記住。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"……일단 뭐라도 먹을까? 토토도 슬슬 배고파 하는데.","JPN":"……とりあえず何か食べようか。\\nトトもそろそろお腹空いてきたみたい。","ENG":"...Should we get something to eat? Toto is starting to get hungry.","TWN":"……先吃點東西吧？托托應該也餓了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"우측 골목을 두 번 돌아서 400m 정도 걸어가면 24시간 식당이 하나 있어. 감자튀김이 끝내준대.","JPN":"右側の路地を2回曲がって400mほど歩くと24時間営業のお店がある。フライドポテトが絶品なんだって。","ENG":"The alley to the right turn two times and walk approximately 400 meters. There will be an all-day diner...They apparently have awesome french fries.","TWN":"從右邊巷子出去後，走400m左右有一家24小時的速食店，聽說那裡的薯條是人間美味。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"토토도 감자튀김 좋아해. 거기로 가면 되겠다.","JPN":"トトもフライドポテトは好きだよ。そこに行こう。","ENG":"Toto also loves french fries. That place should be good.","TWN":"托托也喜歡薯條，就去那裡吃吧！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"좋아. 근데 내 다리가…….","JPN":"いいよ。でも私の脚が……","ENG":"Sure, but my legs...","TWN":"好，可是我的腿……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"옆에 둘이나 있는데 뭐가 걱정이야.","JPN":"ここに二人もいるのに何が心配なの？","ENG":"What are you worried about? You have the two of us with you.","TWN":"有我們兩個在，擔心什麼！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L18_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"부축해 줄게. 천천히 걸어 가자.","JPN":"支えてあげる。ゆっくり歩いて行こう。","ENG":"We will support you. We can walk slowly.","TWN":"我扶你，你慢慢走。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L19_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"……응.","JPN":"……うん。","ENG":"...Okay.","TWN":"……嗯。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"고마워.","JPN":"ありがとう。","ENG":"Thanks.","TWN":"謝謝你們。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};